args.sparql:
SELECT ?city ?cityLabel
WHERE {
  ?city wdt:P31 wd:Q515.
  ?city wdt:P17 wd:Q17.
  ?city wdt:P1352 9.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

SELECT ?site ?siteLabel ?altLabel
WHERE {
  wd:Q276 wdt:P31 wd:Q515 .
  wd:Q276 wdt:P17 wd:Q17 .
  wd:Q276 wdt:P131 ?site .
  ?site wdt:P31 wd:Q15495910 .
  ?site skos:altLabel ?altLabel .
  FILTER (LANG(?altLabel) = 'en')
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

SELECT ?study ?studyLabel
WHERE {
  ?study wdt:P31 wd:Q12548 .
  ?study rdfs:label ?studyLabel .
  FILTER (LANG(?studyLabel) = 'en') .
  FILTER (CONTAINS(LCASE(?studyLabel), 'sanitation')) .
  SERVICE wikibase:label { bd:serviceParam wikibase:language 'en'. }
}

SELECT ?study ?studyLabel
WHERE {
  ?study wdt:P31 wd:Q12548 .
  ?study wdt:P921 wd:Q25481319 .
  ?study rdfs:label ?studyLabel .
  FILTER (LANG(?studyLabel) = 'en') .
  SERVICE wikibase:label { bd:serviceParam wikibase:language 'en'. }
}

SELECT ?site ?siteLabel ?altLabel
WHERE {
  wd:Q748 wdt:P31 wd:Q515 .
  wd:Q748 wdt:P17 wd:Q17 .
  ?site wdt:P131 wd:Q748 .
  ?site wdt:P31 wd:Q15495910 .
  ?site skos:altLabel ?altLabel .
  FILTER (LANG(?altLabel) = 'en')
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
